svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg    = document.getElementById('root');
  var pie    = document.getElementById('pie');
  var ns     = 'http://www.w3.org/2000/svg';

  /* ── depth tinting for quarter slices (icicle reference pattern) ── */
  var PALETTE_LIGHT = {
    1:[0,212,232], 2:[0,184,122], 3:[245,158,11], 4:[244,63,94],
    5:[139,92,246], 6:[59,130,246], 7:[13,148,136], 8:[100,116,139]
  };
  var PALETTE_DARK = {
    1:[34,211,238], 2:[16,185,129], 3:[251,183,36], 4:[251,97,129],
    5:[167,139,250], 6:[96,165,250], 7:[45,212,191], 8:[148,163,184]
  };

  function hexToRgb(h) {
    var n = parseInt(h.replace('#',''), 16);
    return [(n>>16)&255, (n>>8)&255, n&255];
  }

  function blendRgb(base, bgHex, t) {
    var bg = hexToRgb(bgHex);
    return 'rgb('+[0,1,2].map(function(i){
      return Math.round(base[i] + (bg[i]-base[i]) * t);
    }).join(',')+')';
  }

  /* Q1=most blended (lightest), Q4=no blend (full color) */
  var Q_BLENDS_LIGHT = [0.72, 0.48, 0.24, 0.0];
  var Q_BLENDS_DARK = [0.32, 0.18, 0.08, 0.0];

  function recolor() {
    var dark = svgEl.classList.contains('dark');
    var bg = dark ? '#1C1B1F' : '#FFFBFE';
    var blends = dark ? Q_BLENDS_DARK : Q_BLENDS_LIGHT;
    var palette = dark ? PALETTE_DARK : PALETTE_LIGHT;
    pie.querySelectorAll('path[data-arc="o"]').forEach(function(p) {
      var ci = +p.getAttribute('data-ci');
      var qi = +p.getAttribute('data-qi');
      p.style.fill = blendRgb(palette[ci] || [128,128,128], bg, blends[qi]);
    });
  }

  /* ── rAF animation — matches donut reference exactly ── */
  var sliceEls  = Array.prototype.slice.call(pie.querySelectorAll('.slice-g'));
  var holeEl    = document.getElementById('hole-group');
  var STAGGER   = Math.min(250, 1000 / sliceEls.length); /* ms, adaptive */
  var SPIN_DUR  = 550, FADE_DUR = 800;
  var startTime = null;

  function easeOutCubic(t) { return 1 - Math.pow(1-t, 3); }

  /* set initial hidden state via inline style (not CSS) */
  sliceEls.forEach(function(g) { g.style.opacity = '0'; });
  holeEl.style.opacity = '0';

  function animateSlices(ts) {
    if (!startTime) startTime = ts;
    var elapsed = ts - startTime;

    sliceEls.forEach(function(g, i) {
      var tFade = Math.max(0, Math.min(1, (elapsed - i*STAGGER) / FADE_DUR));
      g.style.opacity = easeOutCubic(tFade).toFixed(3);
    });

    var holeStart = (sliceEls.length-1)*STAGGER + SPIN_DUR*0.7;
    holeEl.style.opacity = easeOutCubic(
      Math.max(0, Math.min(1, (elapsed-holeStart)/300))
    ).toFixed(3);

    var totalDur = (sliceEls.length-1)*STAGGER + FADE_DUR + 300;
    if (elapsed < totalDur) {
      requestAnimationFrame(animateSlices);
    } else {
      /* clear inline opacity so CSS hover rules take over cleanly */
      sliceEls.forEach(function(g) { g.style.opacity = ''; });
      holeEl.style.opacity = '1';
      pie.classList.add('ready');
    }
  }

  requestAnimationFrame(animateSlices);

  /* ── tooltip ── */
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipArr = document.getElementById('tip-arr');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');
  var tipPct = document.getElementById('tip-pct');
  var BH=120, TAIL=12, rx9=12, tw=10;

  function showTip(pathEl) {
    var tipX = parseFloat(pathEl.getAttribute('data-tip-x')) + 390;
    var tipY = parseFloat(pathEl.getAttribute('data-tip-y')) + 336;
    tipVal.textContent = pathEl.getAttribute('data-val');
    tipLbl.textContent = pathEl.getAttribute('data-label');
    tipPct.textContent = pathEl.getAttribute('data-pct');

    var pad=20, hw=Math.max(
      tipVal.getBBox().width+pad, tipLbl.getBBox().width+pad,
      tipPct.getBBox().width+pad, 60)/2;

    var bCx = Math.max(hw+8, Math.min(tipX, 1092-hw));
    /* lower half of chart → bubble above; upper half → bubble below */
    var flip = tipY > 336;
    var bT = flip ? tipY-TAIL-BH : tipY+TAIL;
    var bB = bT+BH;
    if (bT<8)   { bT=8;   bB=bT+BH; }
    if (bB>610) { bB=610; bT=bB-BH; }
    var bL=bCx-hw, bR=bCx+hw;

    tipBg.setAttribute('x',bL); tipBg.setAttribute('y',bT);
    tipBg.setAttribute('width',hw*2); tipBg.setAttribute('height',BH);

    var op, tp;
    if (flip) {
      op='M'+(bCx+tw)+','+bB+' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+
         ' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+
         ' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+
         ' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+' L'+(bCx-tw)+','+bB;
      tp='M'+(bCx-tw)+','+bB+' L'+bCx+','+tipY+' L'+(bCx+tw)+','+bB;
    } else {
      op='M'+(bCx-tw)+','+bT+' L'+(bL+rx9)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+rx9)+
         ' L'+bL+','+(bB-rx9)+' Q'+bL+','+bB+' '+(bL+rx9)+','+bB+
         ' L'+(bR-rx9)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-rx9)+
         ' L'+bR+','+(bT+rx9)+' Q'+bR+','+bT+' '+(bR-rx9)+','+bT+' L'+(bCx+tw)+','+bT;
      tp='M'+(bCx+tw)+','+bT+' L'+bCx+','+tipY+' L'+(bCx-tw)+','+bT;
    }
    tipBdr.setAttribute('d',op); tipArr.setAttribute('d',tp);
    tipVal.setAttribute('x',bCx); tipVal.setAttribute('y',bT+BH*0.22);
    tipLbl.setAttribute('x',bCx); tipLbl.setAttribute('y',bT+BH*0.52);
    tipPct.setAttribute('x',bCx); tipPct.setAttribute('y',bT+BH*0.80);
    tip.style.opacity='1';
  }

  /* hover — adjacent slices: container-level mouseleave only.
     Per-element mouseleave removed — it stripped .active mid-traversal between
     adjacent slices, leaving all slices dimmed with none active (flicker).
     Stale-clear on mouseenter handles .active cleanup instead. */
  pie.querySelectorAll('.slice-g').forEach(function(g) {
    var pathEl = g.querySelector('path[data-arc]');
    if (!pathEl) return;
    g.addEventListener('mouseenter', function() {
      pie.classList.add('hovering');
      pie.querySelectorAll('.slice-g').forEach(function(s){ s.classList.remove('active'); });
      g.classList.add('active');
      showTip(pathEl);
    });
  });
  pie.addEventListener('mouseleave', function() {
    pie.querySelectorAll('.slice-g').forEach(function(s){ s.classList.remove('active'); });
    pie.classList.remove('hovering');
    tip.style.opacity='';
  });

  /* ── dark mode ── */
  svgEl._onModeChange = function () { recolor(); };
  recolor();
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
